SELECT method_name
FROM sequence_comparison_methods
WHERE method_id = 1;

SELECT DISTINCT sm.method_id, sm.method_name
FROM sequence_comparison_methods sm
JOIN strain_method_results smr ON sm.method_id = smr.method_id;

WITH LoginCounts AS (
  SELECT user_id, COUNT(*) as login_count
  FROM audit_logs
  GROUP BY user_id
)
SELECT user_id
FROM LoginCounts
WHERE login_count = (
  SELECT MAX(login_count) FROM LoginCounts
);

SELECT * 
FROM genetic_strains 
WHERE strain_name = 'Banana' AND species = 'Vitis vinifera';

SELECT AVG(similarity_coefficient) AS average_similarity_coefficient, AVG(f_value) AS average_f_value
FROM strain_method_results
WHERE similarity_coefficient > 0.5 AND classification = 'Exact match';

SELECT * 
FROM strain_method_results 
WHERE method_id = 1;

SELECT strain_name, species 
FROM genetic_strains 
WHERE strain_id < 10;

SELECT strain_name
FROM genetic_strains
WHERE f_value > (
  SELECT AVG(f_value)
  FROM genetic_strains
);

SELECT COUNT(*)
FROM strain_method_results
WHERE similarity_coefficient > (
    SELECT AVG(similarity_coefficient) 
    FROM strain_method_results
);

SELECT strain_id, strain_name, classification
FROM genetic_strains
WHERE best_match = 'I-IB' AND classification = 'Exact match to Cpn60 UT I-IB';
